import React, { useState } from "react";
import Sidebar from "./components/Sidebar";
import LoginBox from "./components/LoginBox";
import { FaProjectDiagram } from "react-icons/fa";

const AppLayout = ({ children }) => {
  const [showLogin, setShowLogin] = useState(false);
  const [progress, setProgress] = useState(50);

  const toggleLogin = () => {
    setShowLogin(!showLogin);
  };

  return (
    <div className="flex h-screen bg-gray-100">
      {/* Sidebar */}
      <aside className="w-64 bg-gray-900 text-white p-4">
        <Sidebar />
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col items-center relative overflow-hidden">
        {/* Header */}
        <header className="bg-gradient-to-r from-purple-700 to-indigo-800 text-white py-6 px-8 shadow-lg w-full text-center">
          <FaProjectDiagram className="text-5xl text-yellow-300 mb-2" />
          <h1 className="text-2xl font-semibold tracking-wide">
            🚀 Manage Your Projects Efficiently With
          </h1>
          <h2 className="text-4xl font-extrabold text-yellow-300 mt-2">Proma</h2>
        </header>

        {/* Main Content Section */}
        <div className="flex flex-col items-center w-full px-6 py-4 space-y-4 relative">
          {/* Progress Bar */}
          <div className="w-full max-w-lg">
            <div className="w-full bg-gray-300 rounded-full h-4">
              <div
                className="bg-green-500 h-4 rounded-full transition-all"
                style={{ width: `${progress}%` }}
              ></div>
            </div>
            <p className="text-center mt-2 text-gray-700">{progress}% Completed</p>
          </div>

          {/* Login Button */}
          <button
            onClick={toggleLogin}
            className="mt-4 bg-yellow-400 text-black px-4 py-2 rounded-lg font-semibold hover:bg-yellow-500 transition"
          >
            Login
          </button>

          {/* Page Content */}
          <div className="p-6">{children}</div>
        </div>

        {/* Login Box Popup */}
        {showLogin && (
          <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-50 z-50">
            <div className="bg-white p-6 rounded-lg shadow-xl relative w-96">
              <button
                onClick={toggleLogin}
                className="absolute top-2 right-2 text-gray-700 hover:text-gray-900"
              >
                ✖
              </button>
              <LoginBox />
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default AppLayout;
